def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = 0 if item == 0 else np.inf
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if item == 0 and capacity > 0:
            priorities[i] = 0
            continue
        if ratio < 0:
            priorities[i] = np.inf
            continue
        score = 0.0
        decay = 1.0
        penalty = 0.0
        bonus = 1.0
        extra_penalties = 0.0
        adaptive_factor = 0.0
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 5:
            for k1 in range(1, 8):
                for k2 in range(1, 4):
                    penalty += ((ratio ** (2 * k1 + k2)) / ((k1 + k2)**2 + k1)) * ((-1) ** (k1 + k2))
            decay = np.exp(-ratio / 10)
            score = (ratio ** 6) / 3 + penalty
            if item > capacity * 5:
                score *= 4
            else:
                score *= 3
            priorities[i] = score * decay
        elif 3 < ratio <= 5:
            temp = 0
            for x in range(1, 10):
                sign = (-1) ** (x + 1)
                temp += sign * ((ratio ** x) / (x + 1))
            decay = 1.0
            for y in range(1, 6):
                decay *= (1 - 1 / (y + ratio + 2))
            score = abs(temp) * decay * 15
            priorities[i] = score
        elif 2 < ratio <= 3:
            partial_sum = 0
            for p in range(1, 15):
                if p % 3 == 0:
                    partial_sum += (ratio ** p) / (p * 7)
                elif p % 2 == 0:
                    partial_sum -= (ratio ** p) / (p * 4)
                else:
                    partial_sum += (ratio ** p) / (p * 6)
            multiplier = 30 if ratio < 2.5 else 20
            score = abs(partial_sum) * multiplier
            if ratio > 2.8:
                extra = 0
                for m in range(1, 8):
                    extra += (ratio ** m) / (m + 2)
                score += extra * 3
            priorities[i] = score
        elif 1 < ratio <= 2:
            temp_score = 0
            series_len = 20
            for n in range(1, series_len + 1):
                if n % 5 == 0:
                    temp_score += (ratio ** n) / (n * 4)
                elif n % 4 == 0:
                    temp_score -= (ratio ** n) / (n * 6)
                elif n % 3 == 0:
                    temp_score += (ratio ** n) / (n * 3)
                else:
                    temp_score -= (ratio ** n) / (n * 5)
            multiplier = 40 if ratio < 1.3 else 28 if ratio < 1.6 else 18
            score = abs(temp_score) * multiplier
            if 1.85 < ratio < 2:
                extra_penalties = 0
                for q in range(1, 10):
                    extra_penalties += (ratio ** q) / (q * (q + 3))
                score += extra_penalties * 4
            priorities[i] = score
        elif 0 < ratio <= 1:
            temp_score = 0
            for r in range(1, 25):
                if r % 6 == 0:
                    temp_score += (ratio ** r) / (r * 2)
                elif r % 4 == 0:
                    temp_score += (ratio ** r) / (r * 7)
                elif r % 3 == 0:
                    temp_score -= (ratio ** r) / (r * 6)
                else:
                    temp_score -= (ratio ** r) / (r * 5)
            if ratio < 0.1:
                multiplier = 50
            elif ratio < 0.3:
                multiplier = 35
            elif ratio < 0.5:
                multiplier = 20
            elif ratio < 0.7:
                multiplier = 12
            else:
                multiplier = 8
            score = abs(temp_score) * multiplier
            if ratio > 0.9:
                extra_penalties = 0
                for n in range(1, 10):
                    extra_penalties += (ratio ** n) / (n + 1)
                score += extra_penalties * 3
            priorities[i] = score
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
        if priorities[i] != np.inf and bins[i] > 0:
            factor = 1.0
            for z in range(1, 6):
                factor *= (1 + (z ** 2) / (bins[i] + 2))
            adaptive_factor = (np.sin(ratio * np.pi) + 1) / 2
            priorities[i] *= factor * (1 + adaptive_factor)
        elif bins[i] <= 0:
            priorities[i] = np.inf
    return priorities
